u16 FollowerMon_GetGfxID(u16 species, u8 form, BOOL isFemale)
{
    const FollowerMonGfxEntry *entry;
    if (species == SPECIES_NONE || species > SPECIES_ARCEUS) {
        return OBJ_EVENT_GFX_INVISIBLE;
    }
    entry = &sFollowerMonGfxTable[species];
    if (entry->male == 0) {
        return OBJ_EVENT_GFX_INVISIBLE;
    }
    switch (species) {
    case SPECIES_GIRATINA:
        if (form == GIRATINA_FORM_ORIGIN) {
            return OBJ_EVENT_GFX_PKMN_GIRATINA_O;
        }
        break;
    case SPECIES_ARCEUS:
        if (form < ARCEUS_FORM_COUNT) {
            return sArceusFormGfx[form];
        }
        break;
    case SPECIES_DEOXYS:
        switch (form) {
        case DEOXYS_FORM_ATTACK:  return OBJ_EVENT_GFX_PKMN_DEOXYS_ATTACK;
        case DEOXYS_FORM_DEFENSE: return OBJ_EVENT_GFX_PKMN_DEOXYS_DEFENSE;
        case DEOXYS_FORM_SPEED:   return OBJ_EVENT_GFX_PKMN_DEOXYS_SPEED;
        }
        break;
    case SPECIES_BURMY:
        switch (form) {
        case BURMY_FORM_SAND:  return OBJ_EVENT_GFX_PKMN_BURMY_SANDY;
        case BURMY_FORM_TRASH: return OBJ_EVENT_GFX_PKMN_BURMY_TRASH;
        }
        break;
    case SPECIES_WORMADAM:
        switch (form) {
        case WORMADAM_FORM_SAND:  return OBJ_EVENT_GFX_PKMN_WORMADAM_SANDY;
        case WORMADAM_FORM_TRASH: return OBJ_EVENT_GFX_PKMN_WORMADAM_TRASH;
        }
        break;
    case SPECIES_SHELLOS:
        if (form == SHELLOS_FORM_EAST) {
            return OBJ_EVENT_GFX_PKMN_SHELLOS_EAST;
        }
        break;
    case SPECIES_GASTRODON:
        if (form == GASTRODON_FORM_EAST) {
            return OBJ_EVENT_GFX_PKMN_GASTRODON_EAST;
        }
        break;
    case SPECIES_ROTOM:
        switch (form) {
        case ROTOM_FORM_HEAT:  return OBJ_EVENT_GFX_PKMN_ROTOM_HEAT;
        case ROTOM_FORM_WASH:  return OBJ_EVENT_GFX_PKMN_ROTOM_WASH;
        case ROTOM_FORM_FROST: return OBJ_EVENT_GFX_PKMN_ROTOM_FROST;
        case ROTOM_FORM_FAN:   return OBJ_EVENT_GFX_PKMN_ROTOM_FAN;
        case ROTOM_FORM_MOW:   return OBJ_EVENT_GFX_PKMN_ROTOM_MOW;
        }
        break;
    case SPECIES_SHAYMIN:
        if (form == SHAYMIN_FORM_SKY) {
            return OBJ_EVENT_GFX_PKMN_SHAYMIN_SKY;
        }
        break;
    }
    return isFemale ? entry->female : entry->male;
}
